sql:
SELECT employee_id, COUNT(review_id) AS review_count
FROM performance_reviews
GROUP BY employee_id;

SELECT department_id, COUNT(employee_id) AS employee_count
FROM employee_departments
GROUP BY department_id;

SELECT DISTINCT employee_id
FROM employees
WHERE status = 'active';

external_knowledge:
- 'shining stars that outshine the rest like constellations in the night sky' metaphorically refers to the top performers in a department; 
- 'the starry skies they illuminate' symbolizes the department; 
- 'the brightness of their stars' represents the salary amount; 
- 'the reviews that acknowledge their luminosity' symbolizes the review scores and types.

sql:
SELECT COUNT(employee_id) AS total_active_employees
FROM employees
WHERE status = 'active';
